// ===============================
// FECHA ACTUAL (CHILE)
// ===============================
const hoy = new Date();
const offsetChile = -3 * 60;
hoy.setMinutes(hoy.getMinutes() + hoy.getTimezoneOffset() - offsetChile);

// ===============================
// FECHA FIN = DÍA HÁBIL ANTERIOR
// ===============================
const fechaFin = new Date(hoy);
fechaFin.setDate(fechaFin.getDate() - 1);

// Si cae sábado o domingo, retroceder
while (fechaFin.getDay() === 0 || fechaFin.getDay() === 6) {
  fechaFin.setDate(fechaFin.getDate() - 1);
}

// ===============================
// MES ETIQUETA (SEGÚN FECHA FIN)
