const MESES = [
  'ENE','FEB','MAR','ABR','MAY','JUN',
  'JUL','AGO','SEP','OCT','NOV','DIC'
];

const mesEtiqueta = MESES[fechaFin.getMonth()];

// ===============================
// FECHA INICIO = PRIMER DÍA HÁBIL DEL MES
// ===============================
const fechaInicio = new Date(fechaFin.getFullYear(), fechaFin.getMonth(), 1);

// Si cae sábado → lunes
if (fechaInicio.getDay() === 6) {
  fechaInicio.setDate(fechaInicio.getDate() + 2);
}

// Si cae domingo → lunes
if (fechaInicio.getDay() === 0) {
