const repo = $input.first().json;

const inicio = new Date(`${repo.fechaInicio}T00:00:00`);
const fin = new Date(`${repo.fechaFin}T23:59:59`);

let diasLaborables = 0;
let horasTotales = 0;

for (let d = new Date(inicio); d <= fin; d.setDate(d.getDate() + 1)) {
  const dia = d.getDay();

  if (dia >= 1 && dia <= 4) {
    diasLaborables++;
    horasTotales += 8;
  }

  if (dia === 5) {
    diasLaborables++;
    horasTotales += 6.5;
  }
}

return {
  json: {
    fechaInicio: repo.fechaInicio,
    fechaFin: repo.fechaFin,
    diasLaborables,
    horasTotales: +horasTotales.toFixed(1),
    mesCurso: repo.mesEtiqueta,
    personas: repo.personas
  }
};

const calculo = $input.first().json;

return calculo.personas.map(p => ({
  json:{
    personId: p.personId,
    nombreCompleto: `${p.nombre} ${p.apellidoP || ''} ${p.apellidoM || ''}`.trim(),
    area: p.area,
    diasLaborables: calculo.diasLaborables,
    horasEsperadas: calculo.horasTotales,
    fechaInicio: calculo.fechaInicio,
    fechaFin: calculo.fechaFin,
    mesCurso: calculo.mesCurso
  }
}));

// ===============================
// MAPA DE PERSONAS POR personId
// ===============================
const personas = $('Preparar datos personas').all();

const mapa = {};
for (const p of personas) {
  const j = p.json;
  mapa[j.personId] = j;
}

// ===============================
// PROCESO RESPUESTA INTERVALS
// ===============================
const resultados = [];
const responses = $input.all();

for (const item of responses) {
  const registros = item.json.time || [];
  if (!registros.length) continue;

  const personId = Number(registros[0].personid);
  const persona = mapa[personId];
  if (!persona) continue;

  let horasIngresadas = 0;
  for (const r of registros) {
    horasIngresadas += Number(r.time || 0);
  }

  const horasEsperadas = Number(persona.horasEsperadas);
  const diferencia = horasEsperadas - horasIngresadas;
  const semanasPendientes = diferencia > 0 ? diferencia / 40 : 0;
  const porcentaje = horasEsperadas ? (horasIngresadas / horasEsperadas) * 100 : 0;

  let estado =
    porcentaje >= 100 ? '✅ Al día' :
    porcentaje >= 80  ? '⚠️ Advertencia' :
    '❌ Atrasado';

  resultados.push({
    ID: personId,
    Area: persona.area,
    Nombre: persona.nombreCompleto,
    diasLaborables: persona.diasLaborables,
    horasEsperadas: +horasEsperadas.toFixed(2),
    horasIngresadas: +horasIngresadas.toFixed(2),
    diferencia: +diferencia.toFixed(2),
    semanasPendientes: +semanasPendientes.toFixed(1),
    porcentaje: +porcentaje.toFixed(2),
    estado,
    cantidadRegistros: registros.length,
    mesCurso: persona.mesCurso,
    periodoInicio: persona.fechaInicio,
    periodoFin: persona.fechaFin
  });
}

resultados.sort((a,b) => a.diferencia - b.diferencia);
return resultados;

