const datos = $input.all();
const repo = $('Repositorio').first().json;

// ===============================
// FECHAS Y METADATA
// ===============================
const periodoInicio = repo.fechaInicio;
const periodoFin = repo.fechaFin;

const mesCurso = datos.length ? datos[0].json.mesCurso : '';
const diasLaborables = datos.length ? datos[0].json.diasLaborables : 0;

// ===============================
// MÉTRICAS GENERALES
// ===============================
const totalColaboradores = datos.length;
const alDia = datos.filter(i => i.json.estado === '✅ Al día').length;
const advertencia = datos.filter(i => i.json.estado === '⚠️ Advertencia').length;
const atrasados = datos.filter(i => i.json.estado === '❌ Atrasado').length;

// ===============================
// FORMATEO FECHAS ES
// ===============================
const MESES = [
  'enero','febrero','marzo','abril','mayo','junio',
  'julio','agosto','septiembre','octubre','noviembre','diciembre'
];

function formatearFechaES(fechaISO) {
  const [yyyy, mm, dd] = fechaISO.split('-');
  return `${dd} de ${MESES[Number(mm) - 1]}`;
}

const periodoTexto =
  `${formatearFechaES(periodoInicio)} al ${formatearFechaES(periodoFin)}`;

// ===============================
// FILAS TABLA
// ===============================
let filas = '';

